"use strict";(globalThis.webpackChunkdocs_site=globalThis.webpackChunkdocs_site||[]).push([[710],{1072(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"v0210-inline-editing-mcp-autosetup","metadata":{"permalink":"/zh-Hans/blog/v0210-inline-editing-mcp-autosetup","editUrl":"https://github.com/harnspec/harnspec/tree/main/docs-site/blog/2025-12-05-v0210-release.mdx","source":"@site/i18n/zh-Hans/docusaurus-plugin-content-blog/2025-12-05-v0210-release.mdx","title":"HarnSpec 0.2.10\uff1a\u5185\u8054\u5143\u6570\u636e\u7f16\u8f91\u3001MCP \u81ea\u52a8\u914d\u7f6e\u548c\u591a\u9879\u76ee\u6539\u8fdb","description":"HarnSpec 0.2.10 \u5e26\u6765\u4e86\u66f4\u5177\u4ea4\u4e92\u6027\u7684 Web \u4f53\u9a8c\uff1a\u5185\u8054\u5143\u6570\u636e\u7f16\u8f91\u3001\u521d\u59cb\u5316\u65f6\u96f6\u914d\u7f6e MCP \u8bbe\u7f6e\uff0c\u4ee5\u53ca\u591a\u9879\u76ee\u7ba1\u7406\u7684\u91cd\u5927\u6539\u8fdb\u3002\u672c\u6b21\u53d1\u5e03\u4e13\u6ce8\u4e8e\u51cf\u5c11\u6469\u64e6\u2014\u2014\u65e0\u8bba\u60a8\u662f\u5728\u6d4f\u89c8\u5668\u4e2d\u7ba1\u7406 Spec\u3001\u8bbe\u7f6e AI Agent \u96c6\u6210\uff0c\u8fd8\u662f\u8de8\u591a\u4e2a\u9879\u76ee\u5de5\u4f5c\u3002","date":"2025-12-05T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"},{"inline":true,"label":"web-ui","permalink":"/zh-Hans/blog/tags/web-ui"},{"inline":true,"label":"mcp","permalink":"/zh-Hans/blog/tags/mcp"},{"inline":true,"label":"multi-project","permalink":"/zh-Hans/blog/tags/multi-project"}],"readingTime":5.17,"hasTruncateMarker":true,"authors":[{"name":"Marvin Zhang","title":"HarnSpec Author","url":"https://github.com/tikazyq","imageURL":"https://github.com/tikazyq.png","key":"marvin","page":null}],"frontMatter":{"slug":"v0210-inline-editing-mcp-autosetup","title":"HarnSpec 0.2.10\uff1a\u5185\u8054\u5143\u6570\u636e\u7f16\u8f91\u3001MCP \u81ea\u52a8\u914d\u7f6e\u548c\u591a\u9879\u76ee\u6539\u8fdb","authors":["marvin"],"tags":["release","web-ui","mcp","multi-project"]},"unlisted":false,"nextItem":{"title":"HarnSpec \u6700\u65b0\u66f4\u65b0\uff1a\u793a\u4f8b\u9879\u76ee\u3001\u66f4\u5f3a\u5927\u7684\u5de5\u5177\u548c\u5feb\u901f\u4e0a\u624b\u6307\u5357","permalink":"/zh-Hans/blog/recent-updates-getting-started"}},"content":"HarnSpec 0.2.10 \u5e26\u6765\u4e86\u66f4\u5177\u4ea4\u4e92\u6027\u7684 Web \u4f53\u9a8c\uff1a\u5185\u8054\u5143\u6570\u636e\u7f16\u8f91\u3001\u521d\u59cb\u5316\u65f6\u96f6\u914d\u7f6e MCP \u8bbe\u7f6e\uff0c\u4ee5\u53ca\u591a\u9879\u76ee\u7ba1\u7406\u7684\u91cd\u5927\u6539\u8fdb\u3002\u672c\u6b21\u53d1\u5e03\u4e13\u6ce8\u4e8e\u51cf\u5c11\u6469\u64e6\u2014\u2014\u65e0\u8bba\u60a8\u662f\u5728\u6d4f\u89c8\u5668\u4e2d\u7ba1\u7406 Spec\u3001\u8bbe\u7f6e AI Agent \u96c6\u6210\uff0c\u8fd8\u662f\u8de8\u591a\u4e2a\u9879\u76ee\u5de5\u4f5c\u3002\\n\\n**\u4eae\u70b9**\uff1a\u76f4\u63a5\u5728\u6d4f\u89c8\u5668\u4e2d\u7f16\u8f91 Spec \u5143\u6570\u636e\u3001AI \u5de5\u5177\u7684\u81ea\u52a8 MCP \u914d\u7f6e\u3001\u9057\u7559 Spec \u7684 Bootstrap \u6a21\u5f0f\uff0c\u4ee5\u53ca\u66f4\u5b8c\u5584\u7684\u591a\u9879\u76ee\u5de5\u4f5c\u6d41\u3002\\n\\n{/* truncate */}\\n\\n## \u270f\ufe0f Web UI \u5185\u8054\u5143\u6570\u636e\u7f16\u8f91\\n\\n\u65e0\u9700\u518d\u5728 Web \u754c\u9762\u548c\u547d\u4ee4\u884c\u4e4b\u95f4\u5207\u6362\u6765\u66f4\u65b0 Spec \u5143\u6570\u636e\u3002\u73b0\u5728\u60a8\u53ef\u4ee5\u76f4\u63a5\u5728\u6d4f\u89c8\u5668\u4e2d\u7f16\u8f91\u6240\u6709\u5185\u5bb9\uff1a\\n\\n![Spec \u8be6\u60c5\u89c6\u56fe\u4e2d\u7684\u5185\u8054\u5143\u6570\u636e\u7f16\u8f91](/img/blog/v0210/inline-metadata-editing.png)\\n\\n### \u53ef\u7f16\u8f91\u7684\u5185\u5bb9\\n\\n- **Status\uff08\u72b6\u6001\uff09** - \u70b9\u51fb\u72b6\u6001\u5fbd\u7ae0\u53ef\u5728 planned\u3001in-progress\u3001complete \u548c archived \u4e4b\u95f4\u5207\u6362\\n- **Priority\uff08\u4f18\u5148\u7ea7\uff09** - \u5355\u51fb\u5373\u53ef\u66f4\u65b0\u4f18\u5148\u7ea7\uff08low\u3001medium\u3001high\u3001critical\uff09\\n- **Tags\uff08\u6807\u7b7e\uff09** - \u6dfb\u52a0\u3001\u5220\u9664\u6807\u7b7e\uff0c\u652f\u6301\u81ea\u52a8\u8865\u5168\u5efa\u8bae\\n- **Dependencies\uff08\u4f9d\u8d56\uff09** - \u65e0\u9700\u79bb\u5f00 Spec \u89c6\u56fe\u5373\u53ef\u7ba1\u7406 `depends_on` \u5173\u7cfb\\n\\n### \u5de5\u4f5c\u539f\u7406\\n\\n\u66f4\u6539\u91c7\u7528**\u4e50\u89c2\u66f4\u65b0 (Optimistic Update)** \u2014\u2014UI \u7acb\u5373\u66f4\u65b0\uff0c\u4fdd\u5b58\u5728\u540e\u53f0\u8fdb\u884c\u3002\u5982\u679c\u51fa\u73b0\u95ee\u9898\uff0c\u66f4\u6539\u4f1a\u81ea\u52a8\u56de\u6eda\u5e76\u663e\u793a\u6e05\u6670\u7684\u9519\u8bef\u6d88\u606f\u3002\\n\\n\u8fd9\u5728\u6587\u4ef6\u7cfb\u7edf\u6a21\u5f0f\uff08\u672c\u5730\u5f00\u53d1\uff09\u548c\u591a\u9879\u76ee\u6a21\u5f0f\uff08\u56e2\u961f\u4eea\u8868\u677f\uff09\u4e2d\u90fd\u80fd\u6b63\u5e38\u5de5\u4f5c\u3002\\n\\n```bash\\n# \u542f\u52a8 Web UI\\nharnspec ui\\n\\n# \u6216\u4f7f\u7528\u81ea\u5b9a\u4e49\u7aef\u53e3\\nharnspec ui --port 3001\\n```\\n\\n\u6253\u5f00\u4efb\u610f Spec\uff0c\u60a8\u5c06\u5728\u53f3\u4fa7\u770b\u5230\u53ef\u7f16\u8f91\u7684\u5143\u6570\u636e\u9762\u677f\u3002\\n\\n## \ud83d\udd27 Init \u65f6 MCP \u81ea\u52a8\u914d\u7f6e\\n\\n\u8bbe\u7f6e MCP \u670d\u52a1\u5668\u96c6\u6210\u8fc7\u53bb\u9700\u8981\u624b\u52a8\u914d\u7f6e\u3002\u73b0\u5728 `harnspec init` \u4f1a\u81ea\u52a8\u5904\u7406\u3002\\n\\n### \u81ea\u52a8\u68c0\u6d4b\\n\\n\u8fd0\u884c `harnspec init` \u65f6\uff0cHarnSpec \u4f1a\u68c0\u6d4b\u60a8\u7684 AI \u5de5\u5177\u5e76\u63d0\u4f9b MCP \u914d\u7f6e\uff1a\\n\\n```bash\\n$ harnspec init\\n\\n\u2714 Detected AI tools: Claude Code, VS Code, Cursor\\n\\n? Configure MCP server for detected tools? (Y/n) y\\n\\n\u2714 Created .mcp.json for Claude Code\\n\u2714 Created .vscode/mcp.json for VS Code  \\n\u2714 Created .cursor/mcp.json for Cursor\\n```\\n\\n### \u96f6\u624b\u52a8\u914d\u7f6e\\n\\n\u6bcf\u4e2a\u914d\u7f6e\u6587\u4ef6\u90fd\u4f7f\u7528\u6b63\u786e\u7684\u683c\u5f0f\u548c\u7edd\u5bf9\u8def\u5f84\uff1a\\n\\n```json\\n{\\n  \\"mcpServers\\": {\\n    \\"harnspec\\": {\\n      \\"command\\": \\"npx\\",\\n      \\"args\\": [\\"@HarnSpec/mcp\\"],\\n      \\"cwd\\": \\"/absolute/path/to/your/project\\"\\n    }\\n  }\\n}\\n```\\n\\n\u60a8\u7684 AI Agent \u53ef\u4ee5\u7acb\u5373\u8bbf\u95ee HarnSpec \u5de5\u5177\u2014\u2014\u65e0\u9700\u4ece\u6587\u6863\u590d\u5236\u7c98\u8d34\uff0c\u65e0\u9700\u6392\u67e5\u8def\u5f84\u95ee\u9898\u3002\\n\\n### \u652f\u6301\u7684\u5de5\u5177\\n\\n- **Claude Code** - `.mcp.json`\\n- **VS Code** - `.vscode/mcp.json`\\n- **Cursor** - `.cursor/mcp.json`\\n\\n\u66f4\u591a\u5de5\u5177\u5c06\u6839\u636e\u9700\u6c42\u9646\u7eed\u652f\u6301\u3002\\n\\n## \ud83d\udd04 \u9057\u7559 Spec \u7684 Bootstrap \u6a21\u5f0f\\n\\n\u8fc1\u79fb\u7f3a\u5c11 frontmatter \u7684\u73b0\u6709 Spec\uff1f\u65b0\u7684 `--bootstrap` \u6807\u5fd7\u8ba9\u8fd9\u53d8\u5f97\u8f7b\u677e\uff1a\\n\\n```bash\\n# \u4e3a\u6ca1\u6709 frontmatter \u7684 Spec \u521b\u5efa frontmatter\\nharnspec backfill --bootstrap\\n```\\n\\n### Bootstrap \u505a\u4e86\u4ec0\u4e48\\n\\n1. **\u626b\u63cf\u7f3a\u5931\u7684 frontmatter** - \u8bc6\u522b\u6ca1\u6709 YAML \u5143\u6570\u636e\u7684 Spec\\n2. **\u4ece git \u5386\u53f2\u63a8\u65ad\u72b6\u6001** - \u4f7f\u7528\u63d0\u4ea4\u6a21\u5f0f\u63a8\u6d4b\u5f53\u524d\u72b6\u6001\\n3. **\u4ece\u9996\u6b21\u63d0\u4ea4\u8bbe\u7f6e\u521b\u5efa\u65e5\u671f** - \u4ece git \u65e5\u5fd7\u83b7\u53d6\u51c6\u786e\u7684\u65f6\u95f4\u6233\\n4. **\u5904\u7406\u9057\u7559\u683c\u5f0f** - \u8bc6\u522b ADR\u3001RFC \u548c\u5185\u8054\u5143\u6570\u636e\u6a21\u5f0f\\n\\n### \u9057\u7559\u683c\u5f0f\u652f\u6301\\n\\nBootstrap \u7406\u89e3\u5e38\u89c1\u7684\u6587\u6863\u6a21\u5f0f\uff1a\\n\\n- **ADR \u72b6\u6001\u884c**\uff1a`Status: Accepted` \u2192 `status: complete`\\n- **RFC \u5934\u90e8**\uff1a`Status: Proposed` \u2192 `status: planned`\\n- **\u5185\u8054\u5143\u6570\u636e**\uff1a`**Status**: Complete` \u2192 `status: complete`\\n\\n```bash\\n# \u9884\u89c8\u5c06\u8981\u66f4\u6539\u7684\u5185\u5bb9\\nharnspec backfill --bootstrap --dry-run\\n\\n# \u5e94\u7528\u66f4\u6539\\nharnspec backfill --bootstrap\\n```\\n\\n## \ud83d\udcc1 \u591a\u9879\u76ee\u7ba1\u7406\u4f18\u5316\\n\\n\u5bf9\u4e8e\u901a\u8fc7 Web UI \u7ba1\u7406\u591a\u4e2a\u9879\u76ee\u7684\u56e2\u961f\uff0c\u6211\u4eec\u505a\u4e86\u591a\u9879\u6539\u8fdb\uff1a\\n\\n### \u5feb\u901f\u8bbf\u95ee\u9879\u76ee\u7ba1\u7406\\n\\n\u9879\u76ee\u5207\u6362\u4e0b\u62c9\u83dc\u5355\u73b0\u5728\u5305\u542b\\"\u7ba1\u7406\u9879\u76ee\\"\u9009\u9879\u2014\u2014\u65e0\u9700\u518d\u5bfb\u627e\u9879\u76ee\u9875\u9762\u3002\\n\\n### \u5185\u8054\u9879\u76ee\u7f16\u8f91\\n\\n\u76f4\u63a5\u5728 `/projects` \u9875\u9762\u7f16\u8f91\u9879\u76ee\u540d\u79f0\u548c\u989c\u8272\u3002\u70b9\u51fb\u9879\u76ee\u540d\u79f0\u5373\u53ef\u91cd\u547d\u540d\uff0c\u6216\u4f7f\u7528\u989c\u8272\u9009\u62e9\u5668\u81ea\u5b9a\u4e49\u89c6\u89c9\u6807\u8bc6\u3002\\n\\n### \u66f4\u597d\u7684\u8def\u5f84\u5904\u7406\\n\\n- \u957f\u8def\u5f84\u4e0d\u518d\u6ea2\u51fa\u6dfb\u52a0\u9879\u76ee\u5bf9\u8bdd\u6846\\n- \u8def\u5f84\u9a8c\u8bc1\u663e\u793a\u6e05\u6670\u7684\u72b6\u6001\uff08\u6709\u6548/\u65e0\u6548/\u7f3a\u5931\uff09\\n- \u65e0\u6548\u8def\u5f84\u5728\u4fdd\u5b58\u524d\u4f1a\u9ad8\u4eae\u663e\u793a\\n\\n### \u66f4\u667a\u80fd\u7684\u5bfc\u822a\\n\\n\u5f53\u60a8\u4ece Spec \u8be6\u60c5\u9875\u5207\u6362\u9879\u76ee\u65f6\uff0c\u73b0\u5728\u4f1a\u91cd\u5b9a\u5411\u5230\u8be5\u9879\u76ee\u7684 Spec \u5217\u8868\uff0c\u800c\u4e0d\u662f\u663e\u793a 404\u3002\\n\\n## \ud83d\udcca \u4f9d\u8d56\u56fe\uff08v0.2.9 \u529f\u80fd\u56de\u987e\uff09\\n\\n\u5982\u679c\u60a8\u9519\u8fc7\u4e86\u4e0a\u4e2a\u7248\u672c\uff0c\u65b0\u7684 `/dependencies` \u9875\u9762\u8ba9\u60a8\u53ef\u4ee5\u9e1f\u77b0\u6574\u4e2a\u9879\u76ee\u7684\u4f9d\u8d56\u7ed3\u6784\uff1a\\n\\n![\u9879\u76ee\u7ea7\u4f9d\u8d56\u56fe\u53ef\u89c6\u5316](/img/blog/v0210/dependency-graph.png)\\n\\n- **\u4ea4\u4e92\u5f0f DAG \u5e03\u5c40** - \u652f\u6301\u7f29\u653e\u3001\u5e73\u79fb\u548c\u5c0f\u5730\u56fe\u5bfc\u822a\\n- **\u6309\u72b6\u6001\u7b5b\u9009** - \u4e13\u6ce8\u4e8e planned\u3001in-progress \u6216 complete \u7684 Spec\\n- **\u70b9\u51fb\u5bfc\u822a** - \u53cc\u51fb\u4efb\u610f\u8282\u70b9\u6253\u5f00 Spec \u8be6\u60c5\\n- **\u9ad8\u4eae\u4f9d\u8d56\u94fe** - \u9009\u62e9\u4e00\u4e2a Spec \u67e5\u770b\u5176\u5b8c\u6574\u7684\u4f9d\u8d56\u8def\u5f84\\n\\n## \ud83d\udc1b Bug \u4fee\u590d\\n\\n### \u4f9d\u8d56\u9875\u9762\u652f\u6301\u81ea\u5b9a\u4e49\u7aef\u53e3\\n\\n\u4e4b\u524d\uff0c`harnspec ui --port 3002` \u4f1a\u5bfc\u81f4\u4f9d\u8d56\u9875\u9762\u56e0\u786c\u7f16\u7801\u7684 localhost:3000 \u8c03\u7528\u800c\u65e0\u6cd5\u5de5\u4f5c\u3002\u5df2\u4fee\u590d\u2014\u2014\u8be5\u9875\u9762\u73b0\u5728\u652f\u6301\u4efb\u610f\u7aef\u53e3\u3002\\n\\n### \u591a\u9879\u76ee\u4f9d\u8d56\u5df2\u4fee\u590d\\n\\nSpec \u8be6\u60c5\u9875\u4e0a\u7684\\"\u67e5\u770b\u4f9d\u8d56\\"\u6309\u94ae\u73b0\u5728\u5728\u591a\u9879\u76ee\u6a21\u5f0f\u4e0b\u6b63\u5e38\u5de5\u4f5c\uff0c\u4f7f\u7528\u4e86\u65b0\u7684\u4e13\u7528 API \u7aef\u70b9\u3002\\n\\n### MCP `deps` \u5de5\u5177\u6b63\u786e\u67e5\u627e Spec\\n\\n`deps` MCP \u5de5\u5177\u73b0\u5728\u53ef\u4ee5\u6b63\u786e\u901a\u8fc7\u5e8f\u53f7\u89e3\u6790 Spec\uff08\u4f8b\u5982\uff0c`045` \u53ef\u4ee5\u627e\u5230 `045-feature-name`\uff09\u3002\\n\\n### \u6d45\u8272\u4e3b\u9898\u5bf9\u6bd4\u5ea6\\n\\n\u4f9d\u8d56\u9875\u9762\u7684\u8282\u70b9\u73b0\u5728\u5728\u6d45\u8272\u4e3b\u9898\u4e0b\u53ef\u8bfb\u3002\u6211\u4eec\u66f4\u65b0\u4e86\u989c\u8272\u65b9\u6848\uff0c\u786e\u4fdd\u5728\u4e24\u79cd\u4e3b\u9898\u4e0b\u90fd\u6709\u9002\u5f53\u7684\u5bf9\u6bd4\u5ea6\u3002\\n\\n## \u26a1 \u6027\u80fd\uff1a\u66f4\u8f7b\u91cf\u7684 Spec \u5217\u8868\\n\\nSpec \u5217\u8868 API \u4e0d\u518d\u8fd4\u56de\u6bcf\u4e2a Spec \u7684\u5b8c\u6574 `contentMd`\u3002\u5bf9\u4e8e\u6709\u8bb8\u591a Spec \u7684\u9879\u76ee\uff0c\u8fd9\u5c06\u521d\u59cb\u9875\u9762\u52a0\u8f7d\u5927\u5c0f\u51cf\u5c11\u4e86\u7ea6 90%\u3002\\n\\n\u5b8c\u6574\u5185\u5bb9\u5728\u60a8\u6253\u5f00 Spec \u8be6\u60c5\u9875\u65f6\u6309\u9700\u52a0\u8f7d\u3002\\n\\n## \u5347\u7ea7\\n\\n```bash\\n# \u66f4\u65b0\u5168\u5c40\u5b89\u88c5\\nnpm install -g harnspec@latest\\n\\n# \u6216\u4f7f\u7528 npx\uff08\u59cb\u7ec8\u83b7\u53d6\u6700\u65b0\u7248\u672c\uff09\\nnpx harnspec@latest board\\n```\\n\\n\u5982\u679c\u60a8\u4f7f\u7528 MCP \u670d\u52a1\u5668\uff1a\\n\\n```bash\\n# \u66f4\u65b0 MCP \u5305\\nnpm install -g @HarnSpec/mcp@latest\\n```\\n\\n## \u4e0b\u4e00\u6b65\u8ba1\u5212\\n\\n- **VS Code \u6269\u5c55** - \u5728\u7f16\u8f91\u5668\u4e2d\u539f\u751f\u7ba1\u7406 Spec\\n- **GitHub Action** - CI \u4e2d\u7684\u81ea\u52a8\u5316 Spec \u9a8c\u8bc1\\n- **\u66f4\u591a MCP \u5de5\u5177\u6539\u8fdb** - \u6839\u636e\u60a8\u7684\u53cd\u9988\\n\\n**\u6709\u60f3\u6cd5\uff1f** [\u63d0\u4ea4 Issue](https://github.com/codervisor/harnspec/issues) \u6216[\u53d1\u8d77\u8ba8\u8bba](https://github.com/codervisor/harnspec/discussions)\u3002\\n\\n---\\n\\n**\u94fe\u63a5**\uff1a\\n- [\u6587\u6863](https://harnspec.dev/zh-Hans)\\n- [GitHub \u4ed3\u5e93](https://github.com/codervisor/harnspec)\\n- [\u5b8c\u6574\u66f4\u65b0\u65e5\u5fd7](https://github.com/codervisor/harnspec/blob/main/CHANGELOG.md)\\n- [\u5feb\u901f\u5f00\u59cb\u6307\u5357](https://harnspec.dev/zh-Hans/docs/guide/getting-started)"},{"id":"recent-updates-getting-started","metadata":{"permalink":"/zh-Hans/blog/recent-updates-getting-started","editUrl":"https://github.com/harnspec/harnspec/tree/main/docs-site/blog/2025-11-25-recent-updates.mdx","source":"@site/i18n/zh-Hans/docusaurus-plugin-content-blog/2025-11-25-recent-updates.mdx","title":"HarnSpec \u6700\u65b0\u66f4\u65b0\uff1a\u793a\u4f8b\u9879\u76ee\u3001\u66f4\u5f3a\u5927\u7684\u5de5\u5177\u548c\u5feb\u901f\u4e0a\u624b\u6307\u5357","description":"\u6211\u4eec\u4e00\u76f4\u5728\u52aa\u529b\u8ba9 HarnSpec \u66f4\u6613\u4e8e\u4e0a\u624b\u548c\u4f7f\u7528\u3002\u65e0\u8bba\u60a8\u662f\u7b2c\u4e00\u6b21\u63a2\u7d22\u89c4\u683c\u9a71\u52a8\u5f00\u53d1\uff0c\u8fd8\u662f\u9700\u8981\u6269\u5c55\u5230\u4f01\u4e1a\u7ea7\u5de5\u4f5c\u6d41\uff0c\u8fd9\u4e9b\u66f4\u65b0\u90fd\u5c06\u52a0\u901f\u60a8\u4ece\u610f\u56fe\u5230\u53ef\u8fd0\u884c\u4ee3\u7801\u7684\u65c5\u7a0b\u3002","date":"2025-11-25T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"},{"inline":true,"label":"getting-started","permalink":"/zh-Hans/blog/tags/getting-started"},{"inline":true,"label":"tutorials","permalink":"/zh-Hans/blog/tags/tutorials"}],"readingTime":5.63,"hasTruncateMarker":true,"authors":[{"name":"Marvin Zhang","title":"HarnSpec Author","url":"https://github.com/tikazyq","imageURL":"https://github.com/tikazyq.png","key":"marvin","page":null}],"frontMatter":{"slug":"recent-updates-getting-started","title":"HarnSpec \u6700\u65b0\u66f4\u65b0\uff1a\u793a\u4f8b\u9879\u76ee\u3001\u66f4\u5f3a\u5927\u7684\u5de5\u5177\u548c\u5feb\u901f\u4e0a\u624b\u6307\u5357","authors":["marvin"],"tags":["release","getting-started","tutorials"]},"unlisted":false,"prevItem":{"title":"HarnSpec 0.2.10\uff1a\u5185\u8054\u5143\u6570\u636e\u7f16\u8f91\u3001MCP \u81ea\u52a8\u914d\u7f6e\u548c\u591a\u9879\u76ee\u6539\u8fdb","permalink":"/zh-Hans/blog/v0210-inline-editing-mcp-autosetup"},"nextItem":{"title":"\u4e3a\u4ec0\u4e48\u5927\u578b\u89c4\u8303\u4f1a\u8ba9\u4f60\u7684 AI \u4ee3\u7406\u53d8\u7b28\uff08\u4ee5\u53ca\u5982\u4f55\u89e3\u51b3\uff09","permalink":"/zh-Hans/blog/ai-agent-performance"}},"content":"\u6211\u4eec\u4e00\u76f4\u5728\u52aa\u529b\u8ba9 HarnSpec \u66f4\u6613\u4e8e\u4e0a\u624b\u548c\u4f7f\u7528\u3002\u65e0\u8bba\u60a8\u662f\u7b2c\u4e00\u6b21\u63a2\u7d22\u89c4\u683c\u9a71\u52a8\u5f00\u53d1\uff0c\u8fd8\u662f\u9700\u8981\u6269\u5c55\u5230\u4f01\u4e1a\u7ea7\u5de5\u4f5c\u6d41\uff0c\u8fd9\u4e9b\u66f4\u65b0\u90fd\u5c06\u52a0\u901f\u60a8\u4ece\u610f\u56fe\u5230\u53ef\u8fd0\u884c\u4ee3\u7801\u7684\u65c5\u7a0b\u3002\\n\\n**\u65b0\u529f\u80fd\u4eae\u70b9**\uff1a\u793a\u4f8b\u9879\u76ee\u5b9e\u73b0\u5373\u65f6\u4e0a\u624b\u5b66\u4e60\u3001JSON \u8f93\u51fa\u652f\u6301\u81ea\u52a8\u5316\u3001\u7b80\u5316\u7684\u6a21\u677f\u7cfb\u7edf\uff0c\u4ee5\u53ca MCP \u670d\u52a1\u5668\u96c6\u6210\u7684\u91cd\u5927\u6539\u8fdb\u3002\\n\\n{/* truncate */}\\n\\n## \ud83d\ude80 \u793a\u4f8b\u9879\u76ee\uff1a\u51e0\u79d2\u949f\u5f00\u59cb\u5b66\u4e60\\n\\n\u7406\u89e3 HarnSpec \u7684\u6700\u4f73\u65b9\u5f0f\u5c31\u662f\u4f7f\u7528\u5b83\u3002\u8fd9\u5c31\u662f\u6211\u4eec\u6784\u5efa**\u793a\u4f8b\u9879\u76ee\u811a\u624b\u67b6**\u7684\u539f\u56e0\u2014\u2014\u5b8c\u6574\u7684\u6559\u7a0b\u9879\u76ee\uff0c\u60a8\u53ef\u4ee5\u7acb\u5373\u542f\u52a8\u3002\\n\\n### \u4e09\u4e2a\u5f00\u7bb1\u5373\u7528\u7684\u793a\u4f8b\\n\\n```bash\\n# \u67e5\u770b\u53ef\u7528\u793a\u4f8b\\nnpx harnspec examples\\n\\n# \u521d\u59cb\u5316\u793a\u4f8b\u9879\u76ee\\nnpx harnspec init --example dark-theme\\ncd dark-theme\\nnpm install\\nnpm start\\n```\\n\\n\u6bcf\u4e2a\u793a\u4f8b\u90fd\u5305\u542b\uff1a\\n- \u2705 **\u5b8c\u6574\u7684\u542f\u52a8\u4ee3\u7801** - \u53ef\u4ee5\u7acb\u5373\u6784\u5efa\u7684\u5de5\u4f5c React \u5e94\u7528\\n- \u2705 **HarnSpec \u5df2\u521d\u59cb\u5316** - Spec\u3001\u6a21\u677f\u548c\u914d\u7f6e\u5df2\u5c31\u7eea\\n- \u2705 **\u771f\u5b9e\u7684\u529f\u80fd Spec** - \u53ef\u4ee5\u9075\u5faa\u7684\u771f\u5b9e\u793a\u4f8b\\n- \u2705 **\u6559\u7a0b\u53cb\u597d** - \u4e13\u4e3a\u914d\u5408\u6211\u4eec\u7684[\u5b9e\u8df5\u6559\u7a0b](/zh-Hans/docs/tutorials/first-spec-with-ai)\u8bbe\u8ba1\\n\\n#### \u53ef\u7528\u793a\u4f8b\\n\\n**`dark-theme`** - \u4e3a React \u5e94\u7528\u6dfb\u52a0\u6697\u9ed1\u6a21\u5f0f  \\n\u5b8c\u7f8e\u7684\u7b2c\u4e00\u4e2a\u9879\u76ee\u3002\u5b66\u4e60\u57fa\u7840\uff1a\u521b\u5efa Spec\u3001\u4e0e AI \u534f\u4f5c\u3001\u8ddf\u8e2a\u8fdb\u5ea6\u3002\\n\\n**`dashboard-widgets`** - \u6784\u5efa\u53ef\u81ea\u5b9a\u4e49\u7684\u4eea\u8868\u677f  \\n\u591a\u7ec4\u4ef6\u529f\u80fd\u3002\u7ec3\u4e60\u62c6\u5206 Spec\u3001\u7ba1\u7406\u590d\u6742\u6027\u3001\u4f7f\u7528\u5b50 Spec\u3002\\n\\n**`api-refactor`** - \u5c06 REST API \u73b0\u4ee3\u5316\u4e3a GraphQL  \\n\u540e\u7aef\u4e13\u6ce8\u793a\u4f8b\u3002\u4e86\u89e3 HarnSpec \u5982\u4f55\u5904\u7406\u67b6\u6784\u53d8\u66f4\u548c\u8fc1\u79fb\u3002\\n\\n### \u4e3a\u4ec0\u4e48\u8fd9\u5f88\u91cd\u8981\\n\\n**\u6709\u793a\u4f8b\u9879\u76ee\u4e4b\u524d\uff1a**\\n- \\"\u5982\u4f55\u6784\u5efa Spec\uff1f\\" \u2192 \u9605\u8bfb\u6587\u6863\u3001\u731c\u6d4b\u3001\u8fed\u4ee3\\n- \\"\u771f\u5b9e\u7684 Spec \u957f\u4ec0\u4e48\u6837\uff1f\\" \u2192 \u6d4f\u89c8 GitHub\u3001\u9002\u914d\u5230\u60a8\u7684\u9879\u76ee\\n- \\"\u8fd9\u80fd\u4e0e\u6211\u7684 AI \u5de5\u5177\u914d\u5408\u5417\uff1f\\" \u2192 \u5c1d\u8bd5\u3001\u8c03\u8bd5\u3001\u6392\u67e5\\n\\n**\u6709\u793a\u4f8b\u9879\u76ee\u4e4b\u540e\uff1a**\\n- \u514b\u9686\u3002\u8fd0\u884c\u3002\u5f00\u59cb\u7f16\u7801\u3002\\n- \u4f7f\u7528\u53ef\u8fd0\u884c\u7684\u4ee3\u7801\u8ddf\u968f\u6559\u7a0b\u3002\\n- \u6e05\u695a\u5730\u770b\u5230 Spec \u5982\u4f55\u5f15\u5bfc AI Agent\u3002\\n\\n\u4e0d\u518d\u6709\u7a7a\u767d\u9875\u7efc\u5408\u75c7\u3002\u4e0d\u518d\u6709\\"\u4ece\u54ea\u91cc\u5f00\u59cb\uff1f\\"\u53ea\u6709\u7acb\u5373\u89c1\u6548\u7684\u5b9e\u8df5\u5b66\u4e60\u3002\\n\\n## \ud83e\udd16 \u66f4\u597d\u7684 AI \u96c6\u6210\\n\\n### MCP \u670d\u52a1\u5668\u4f5c\u4e3a\u72ec\u7acb\u5305\\n\\n\u6211\u4eec\u5c06 `@HarnSpec/mcp` \u63d0\u53d6\u4e3a\u72ec\u7acb\u7684 npm \u5305\u3002\u73b0\u5728\u8bbe\u7f6e\u66f4\u7b80\u6d01\uff1a\\n\\n```json\\n{\\n  \\"mcpServers\\": {\\n    \\"harnspec\\": {\\n      \\"command\\": \\"npx\\",\\n      \\"args\\": [\\"@HarnSpec/mcp\\"]\\n    }\\n  }\\n}\\n```\\n\\n\u9002\u7528\u4e8e Claude Desktop\u3001Cline\u3001Zed \u548c\u4efb\u4f55\u517c\u5bb9 MCP \u7684\u5de5\u5177\u3002\u8be5\u670d\u52a1\u5668\u8ba9 AI Agent \u76f4\u63a5\u8bbf\u95ee\u60a8\u7684 Spec\u2014\u2014\u65e0\u9700\u590d\u5236\u7c98\u8d34\uff0c\u65e0\u4e0a\u4e0b\u6587\u9650\u5236\u3002\\n\\n### \u589e\u5f3a\u7684\u4f9d\u8d56\u7ba1\u7406\\n\\n\u65b0\u547d\u4ee4\u8ba9\u5173\u7cfb\u7ba1\u7406\u66f4\u6e05\u6670\uff1a\\n\\n```bash\\n# \u4f7f\u7528\u660e\u786e\u7684\u4f9d\u8d56\u5173\u7cfb\u94fe\u63a5 Spec\\nharnspec link feature-123 --depends-on auth-system\\n\\n# \u67e5\u770b\u5b8c\u6574\u7684\u4f9d\u8d56\u56fe\\nharnspec deps feature-123\\n\\n# \u5220\u9664\u5173\u7cfb\\nharnspec unlink feature-123 --from auth-system\\n```\\n\\n\u66f4\u597d\u7684\u9a8c\u8bc1\u5728\u95ee\u9898\u53d1\u751f\u524d\u6355\u83b7\u5faa\u73af\u4f9d\u8d56\u3002\\n\\n## \ud83d\udd27 \u652f\u6301\u81ea\u52a8\u5316\u7684 JSON \u8f93\u51fa\\n\\n\u6240\u6709\u4e3b\u8981\u547d\u4ee4\u73b0\u5728\u90fd\u652f\u6301 `--json` \u7528\u4e8e\u7f16\u7a0b\u5f0f\u4f7f\u7528\uff1a\\n\\n```bash\\n# \u96c6\u6210\u5230\u4eea\u8868\u677f\\nharnspec board --json | jq \'.columns[] | select(.status==\\"in-progress\\")\'\\n\\n# \u6784\u5efa\u81ea\u5b9a\u4e49\u5de5\u4f5c\u6d41\\nharnspec list --json --status=complete | jq -r \'.[] | .name\'\\n\\n# \u5bfc\u51fa\u7528\u4e8e\u62a5\u544a\\nharnspec timeline --json > project-timeline.json\\n```\\n\\n\u5728 CI/CD \u6d41\u6c34\u7ebf\u3001\u9879\u76ee\u4eea\u8868\u677f\u6216\u81ea\u5b9a\u4e49\u5de5\u5177\u4e2d\u4f7f\u7528 HarnSpec \u6570\u636e\u3002\\n\\n## \ud83d\udcdd \u7b80\u5316\u7684\u6a21\u677f\u7cfb\u7edf\\n\\n\u6211\u4eec\u79fb\u9664\u4e86 Handlebars \u6a21\u677f\u5c42\u3002\u6a21\u677f\u73b0\u5728**\u53ea\u662f Markdown \u6587\u4ef6**\uff0c\u60a8\u53ef\u4ee5\u76f4\u63a5\u7f16\u8f91\u3002\\n\\n**\u4e4b\u524d**\uff1a\u7f16\u8f91 `.hbs` \u6587\u4ef6 \u2192 \u8fd0\u884c\u6784\u5efa \u2192 \u6d4b\u8bd5  \\n**\u4e4b\u540e**\uff1a\u7f16\u8f91 `.md` \u6587\u4ef6 \u2192 \u6d4b\u8bd5\\n\\n\u4e24\u4e2a\u6a21\u677f\u6db5\u76d6\u6240\u6709\u573a\u666f\uff1a\\n- **`standard`**\uff08\u9ed8\u8ba4\uff09- \u5927\u591a\u6570\u529f\u80fd\u7684\u5355\u6587\u4ef6 Spec\\n- **`detailed`** - \u6f14\u793a\u5b50 Spec \u7684\u591a\u6587\u4ef6\u793a\u4f8b\\n\\n\u65e0\u9700\u6784\u5efa\u6b65\u9aa4\uff0c\u65e0\u9700\u5b66\u4e60\u6a21\u677f\u5f15\u64ce\u3002\u53ea\u9700 Markdown\u3002\\n\\n## \ud83c\udf0f \u4e13\u4e1a\u7684\u4e2d\u6587\u7ffb\u8bd1\\n\\n\u5982\u679c\u60a8\u4e0e\u4e2d\u6587\u56e2\u961f\u5408\u4f5c\uff0c\u6211\u4eec\u7684\u6587\u6863\u73b0\u5df2\u5168\u9762\u672c\u5730\u5316\uff0c\u63d0\u4f9b\u4e13\u4e1a\u7ffb\u8bd1\u3002\u6211\u4eec\u5efa\u7acb\u4e86\u4e25\u683c\u7684\u8d28\u91cf\u6807\u51c6\uff1a\\n\\n- \u6280\u672f\u672f\u8bed\u4fdd\u6301\u82f1\u6587\uff08Spec\u3001CLI\u3001Token\u3001MCP\uff09\\n- \u81ea\u7136\u7684\u4e2d\u6587\u8868\u8fbe\uff08\u975e\u9010\u5b57\u7ffb\u8bd1\uff09\\n- \u6240\u6709\u6587\u6863\u4e2d\u7684\u4e00\u81f4\u672f\u8bed\\n- \u5b8c\u6574\u8986\u76d6\u6307\u5357\u3001\u6559\u7a0b\u548c API \u53c2\u8003\\n\\n\u8bbf\u95ee [harnspec.dev/zh-Hans](https://harnspec.dev/zh-Hans) \u67e5\u770b\u4e2d\u6587\u6587\u6863\u3002\\n\\n## \ud83c\udfaf \u5feb\u901f\u4e0a\u624b\u8def\u5f84\\n\\n\u4e0d\u786e\u5b9a\u4ece\u54ea\u91cc\u5f00\u59cb\uff1f\u8fd9\u662f\u63a8\u8350\u7684\u8def\u5f84\uff1a\\n\\n### 1. \u7406\u89e3\u539f\u56e0\uff085 \u5206\u949f\uff09\\n\\n\u9605\u8bfb[\u4e3a\u4ec0\u4e48\u60a8\u7684 AI Agent \u5728\u5927\u578b Spec \u4e2d\u53d8\u7b28](/zh-Hans/blog/ai-agent-performance)\uff0c\u4e86\u89e3 HarnSpec \u80cc\u540e\u7684\u4e0a\u4e0b\u6587\u5de5\u7a0b (Context Engineering) \u539f\u5219\u3002\\n\\n**\u6838\u5fc3\u8981\u70b9**\uff1a\u8fd9\u4e0d\u662f\u5173\u4e8e\u9002\u5e94\u4e0a\u4e0b\u6587\u7a97\u53e3\u2014\u2014\u800c\u662f\u5173\u4e8e\u5728\u9879\u76ee\u89c4\u6a21\u6269\u5927\u65f6\u4fdd\u6301 AI \u6027\u80fd\u3002\\n\\n### 2. \u542f\u52a8\u793a\u4f8b\u9879\u76ee\uff082 \u5206\u949f\uff09\\n\\n```bash\\nnpx harnspec init --example dark-theme\\ncd dark-theme\\nnpm install\\n```\\n\\n\u73b0\u5728\u60a8\u6709\u4e86\u4e00\u4e2a\u5df2\u914d\u7f6e\u597d HarnSpec \u7684\u53ef\u8fd0\u884c React \u5e94\u7528\u3002\\n\\n### 3. \u8ddf\u968f\u6559\u7a0b\uff0810 \u5206\u949f\uff09\\n\\n\u6253\u5f00[\u4f7f\u7528 AI \u521b\u5efa\u60a8\u7684\u7b2c\u4e00\u4e2a Spec](/zh-Hans/docs/tutorials/first-spec-with-ai) \u6559\u7a0b\u3002\u5b83\u5c06\u5f15\u5bfc\u60a8\u5b8c\u6210\uff1a\\n\\n- \u521b\u5efa\u60a8\u7684\u7b2c\u4e00\u4e2a Spec\\n- \u4e0e AI \u534f\u4f5c\u5b9e\u73b0\u529f\u80fd\\n- \u8ddf\u8e2a\u8fdb\u5ea6\u5e76\u5b8c\u6210\u5de5\u4f5c\\n- \u4e86\u89e3 Spec \u5982\u4f55\u5f15\u5bfc AI \u884c\u4e3a\\n\\n**\u4f7f\u7528\u60a8\u521a\u521a\u521d\u59cb\u5316\u7684\u793a\u4f8b\u9879\u76ee**\u2014\u2014\u5b83\u4e13\u4e3a\u6b64\u6559\u7a0b\u8bbe\u8ba1\u3002\\n\\n### 4. \u5728\u81ea\u5df1\u7684\u9879\u76ee\u4e2d\u5c1d\u8bd5\uff08\u51c6\u5907\u597d\u65f6\uff09\\n\\n```bash\\ncd your-existing-project\\nnpx harnspec init\\nharnspec create user-authentication\\n```\\n\\n\u73b0\u5728\u5e94\u7528\u60a8\u5b66\u5230\u7684\u77e5\u8bc6\u3002\u4ece\u7b80\u5355\u5f00\u59cb\uff08status + created\uff09\uff0c\u6839\u636e\u9700\u8981\u6dfb\u52a0\u7ed3\u6784\uff08tags\u3001priority\u3001\u81ea\u5b9a\u4e49\u5b57\u6bb5\uff09\u3002\\n\\n### \u9700\u8981\u66f4\u591a\u6307\u5bfc\uff1f\\n\\n- **\u5c0f\u529f\u80fd**\uff1a[\u60a8\u7684\u7b2c\u4e00\u4e2a Spec](/zh-Hans/docs/tutorials/first-spec-with-ai)\\n- **\u591a\u4e2a\u76f8\u5173\u529f\u80fd**\uff1a[\u7ba1\u7406\u591a\u4e2a\u529f\u80fd](/zh-Hans/docs/tutorials/managing-multiple-features)\\n- **\u5927\u578b\u9879\u76ee**\uff1a[\u5927\u578b\u9879\u76ee\u7ba1\u7406](/zh-Hans/docs/tutorials/large-project-management)\\n- **\u9057\u7559\u4ee3\u7801\u5e93**\uff1a[\u4f7f\u7528 Spec \u91cd\u6784](/zh-Hans/docs/tutorials/refactoring-with-specs)\\n\\n## \u4e0b\u4e00\u6b65\u8ba1\u5212\\n\\n\u6211\u4eec\u4e13\u6ce8\u4e8e\u8ba9 HarnSpec \u4e0e\u66f4\u591a AI \u5de5\u5177\u548c\u5f00\u53d1\u5de5\u4f5c\u6d41\u65e0\u7f1d\u914d\u5408\uff1a\\n\\n- **GitHub Copilot Workspace \u96c6\u6210** - \u5728 Copilot \u7684\u4efb\u52a1\u89c4\u5212\u4e2d\u539f\u751f\u652f\u6301 Spec\\n- **VS Code \u6269\u5c55** - \u5185\u8054 Spec \u67e5\u770b\u3001\u9a8c\u8bc1\u548c\u72b6\u6001\u8ddf\u8e2a\\n- **\u9879\u76ee\u7ba1\u7406\u96c6\u6210** - Jira\u3001Linear \u548c GitHub Projects \u540c\u6b65\\n- **\u66f4\u591a\u793a\u4f8b\u9879\u76ee** - \u540e\u7aef API\u3001\u79fb\u52a8\u5e94\u7528\u3001\u57fa\u7840\u8bbe\u65bd\\n\\n**\u53cd\u9988\u5851\u9020\u8def\u7ebf\u56fe**\u3002\u4ec0\u4e48\u80fd\u8ba9 HarnSpec \u5bf9\u60a8\u7684\u5de5\u4f5c\u6d41\u66f4\u6709\u7528\uff1f[\u63d0\u4ea4 Issue](https://github.com/codervisor/harnspec/issues) \u6216[\u53c2\u4e0e\u8ba8\u8bba](https://github.com/codervisor/harnspec/discussions)\u3002\\n\\n## \u7acb\u5373\u5c1d\u8bd5\\n\\n```bash\\n# \u5168\u5c40\u5b89\u88c5\\nnpm install -g harnspec\\n\\n# \u6216\u4f7f\u7528 npx \u4e00\u6b21\u6027\u547d\u4ee4\\nnpx harnspec init --example dark-theme\\n```\\n\\n\u5b66\u4e60\u7684\u6700\u5feb\u65b9\u5f0f\u5c31\u662f\u6784\u5efa\u3002\u9009\u62e9\u4e00\u4e2a\u793a\u4f8b\uff0c\u8ddf\u968f\u6559\u7a0b\uff0c\u770b\u770b AI \u8f85\u52a9\u7684\u89c4\u683c\u9a71\u52a8\u5f00\u53d1\u5982\u4f55\u6539\u53d8\u60a8\u7684\u5de5\u4f5c\u6d41\u3002\\n\\n---\\n\\n**\u94fe\u63a5**\uff1a\\n- [\u6587\u6863](https://harnspec.dev/zh-Hans)\\n- [GitHub \u4ed3\u5e93](https://github.com/codervisor/harnspec)\\n- [\u793a\u4f8b\u9879\u76ee](https://harnspec.dev/zh-Hans/docs/tutorials/first-spec-with-ai#quick-start)\\n- [\u5feb\u901f\u5f00\u59cb\u6307\u5357](https://harnspec.dev/zh-Hans/docs/guide/getting-started)\\n- [\u5b8c\u6574\u6559\u7a0b\u96c6\u5408](https://harnspec.dev/zh-Hans/docs/tutorials/first-spec-with-ai)\\n\\n**\u66f4\u65b0\u65e5\u5fd7**\uff1a\u8be6\u7ec6\u7248\u672c\u5386\u53f2\u8bf7\u53c2\u9605 [CHANGELOG.md](https://github.com/codervisor/harnspec/blob/main/CHANGELOG.md)\u3002"},{"id":"ai-agent-performance","metadata":{"permalink":"/zh-Hans/blog/ai-agent-performance","editUrl":"https://github.com/harnspec/harnspec/tree/main/docs-site/blog/2025-11-10-ai-agent-performance.mdx","source":"@site/i18n/zh-Hans/docusaurus-plugin-content-blog/2025-11-10-ai-agent-performance.mdx","title":"\u4e3a\u4ec0\u4e48\u5927\u578b\u89c4\u8303\u4f1a\u8ba9\u4f60\u7684 AI \u4ee3\u7406\u53d8\u7b28\uff08\u4ee5\u53ca\u5982\u4f55\u89e3\u51b3\uff09","description":"\u4f60\u7684\u89c4\u8303\u80fd\u88c5\u8fdb\u4e0a\u4e0b\u6587\u7a97\u53e3\u3002\u90a3\u4e3a\u4ec0\u4e48\u4f60\u7684 AI \u4ee3\u7406\u4f1a\u72af\u9519\u3001\u5ffd\u7565\u6307\u4ee4\u3001\u4ea7\u51fa\u66f4\u5dee\u7684\u4ee3\u7801\u5462\uff1f","date":"2025-11-10T00:00:00.000Z","tags":[{"inline":true,"label":"ai","permalink":"/zh-Hans/blog/tags/ai"},{"inline":true,"label":"context-engineering","permalink":"/zh-Hans/blog/tags/context-engineering"},{"inline":true,"label":"best-practices","permalink":"/zh-Hans/blog/tags/best-practices"}],"readingTime":8.16,"hasTruncateMarker":true,"authors":[{"name":"Marvin Zhang","title":"HarnSpec Author","url":"https://github.com/tikazyq","imageURL":"https://github.com/tikazyq.png","key":"marvin","page":null}],"frontMatter":{"slug":"ai-agent-performance","title":"\u4e3a\u4ec0\u4e48\u5927\u578b\u89c4\u8303\u4f1a\u8ba9\u4f60\u7684 AI \u4ee3\u7406\u53d8\u7b28\uff08\u4ee5\u53ca\u5982\u4f55\u89e3\u51b3\uff09","authors":["marvin"],"tags":["ai","context-engineering","best-practices"]},"unlisted":false,"prevItem":{"title":"HarnSpec \u6700\u65b0\u66f4\u65b0\uff1a\u793a\u4f8b\u9879\u76ee\u3001\u66f4\u5f3a\u5927\u7684\u5de5\u5177\u548c\u5feb\u901f\u4e0a\u624b\u6307\u5357","permalink":"/zh-Hans/blog/recent-updates-getting-started"},"nextItem":{"title":"\u6b22\u8fce\u4f7f\u7528 HarnSpec","permalink":"/zh-Hans/blog/welcome"}},"content":"\u4f60\u7684\u89c4\u8303\u80fd\u88c5\u8fdb\u4e0a\u4e0b\u6587\u7a97\u53e3\u3002\u90a3\u4e3a\u4ec0\u4e48\u4f60\u7684 AI \u4ee3\u7406\u4f1a\u72af\u9519\u3001\u5ffd\u7565\u6307\u4ee4\u3001\u4ea7\u51fa\u66f4\u5dee\u7684\u4ee3\u7801\u5462\uff1f\\n\\n\u4f60\u628a\u4e00\u4efd\u8be6\u7ec6\u7684 2,000 \u884c\u67b6\u6784\u6587\u6863\u7c98\u8d34\u5230 Cursor \u4e2d\u3002\u4e0a\u4e0b\u6587\u7a97\u53e3\u80fd\u5904\u7406\u2014\u201420 \u4e07\u4ee4\u724c\uff0c\u7a7a\u95f4\u8db3\u591f\u3002\u4f46\u6709\u4e9b\u4e0d\u5bf9\u52b2\u3002AI \u5efa\u8bae\u4e86\u4e00\u79cd\u4f60\u5728\u7b2c 3 \u9875\u660e\u786e\u6392\u9664\u7684\u65b9\u6cd5\u3002\u5b83\u95ee\u4e86\u4f60\u5df2\u7ecf\u56de\u7b54\u8fc7\u7684\u95ee\u9898\u3002\u5b83\u751f\u6210\u7684\u4ee3\u7801\u4e0e\u4f60\u8bb0\u5f55\u7684\u8bbe\u8ba1\u51b3\u7b56\u76f8\u77db\u76fe\u3002\\n\\n**\u95ee\u9898\u4e0d\u5728\u4e0a\u4e0b\u6587\u5927\u5c0f\u3002\u800c\u5728\u4e0a\u4e0b\u6587\u8d28\u91cf\u3002**\\n\\n{/* truncate */}\\n\\n## \u771f\u6b63\u7684\u95ee\u9898\uff1a\u6027\u80fd\u4e0b\u964d\\n\\n\u73b0\u4ee3 AI \u6a21\u578b\u6709\u5de8\u5927\u7684\u4e0a\u4e0b\u6587\u7a97\u53e3\u2014\u2014Claude \u6709 20 \u4e07\u4ee4\u724c\uff0cGPT \u6709 12.8 \u4e07\uff0c\u66f4\u65b0\u7684\u6a21\u578b\u6b63\u5728\u63a8\u5411 100 \u4e07\u4ee5\u4e0a\u3002\u4f46\u8425\u9500\u4e0d\u4f1a\u544a\u8bc9\u4f60\u7684\u662f\uff1a**\u5373\u4f7f\u8fdc\u672a\u8fbe\u5230\u4e0a\u9650\uff0cAI \u6027\u80fd\u4e5f\u4f1a\u968f\u7740\u4e0a\u4e0b\u6587\u589e\u957f\u800c\u663e\u8457\u4e0b\u964d**\u3002\\n\\n\u7814\u7a76\u7ed3\u679c\u5f88\u6e05\u695a\uff1a\\n\\n**Databricks \u53d1\u73b0**[\u957f\u4e0a\u4e0b\u6587\u6027\u80fd\u663e\u8457\u4e0b\u964d](https://www.databricks.com/blog/long-context-rag-performance-llms)\uff0c\u5373\u4f7f\u5728\u7406\u8bba\u9650\u5236\u5185\u3002\u8f83\u5c0f\u7684\u6a21\u578b\u4e0b\u964d\u5f97\u66f4\u65e9\u3002\\n\\n**\u4f2f\u514b\u5229\u7684[\u51fd\u6570\u8c03\u7528\u6392\u884c\u699c](https://gorilla.cs.berkeley.edu/leaderboard.html)** \u8bc1\u5b9e\uff0c\u5f53\u7ed9\u51fa\u66f4\u591a\u5de5\u5177\u6216\u9009\u9879\u65f6\uff0c\u6240\u6709\u6a21\u578b\u7684\u6027\u80fd\u90fd\u4f1a\u4e0b\u964d\u3002\u66f4\u591a\u4e0a\u4e0b\u6587 = \u66f4\u591a\u56f0\u60d1 = \u66f4\u4f4e\u51c6\u786e\u6027\u3002\\n\\n**\u7814\u7a76\u663e\u793a**\uff08[arXiv:2505.06120](https://arxiv.org/pdf/2505.06120)\uff09\u5f53\u6a21\u578b\u9700\u8981\u8de8\u591a\u4e2a\u4e0a\u4e0b\u6587\u8f6e\u6b21\u5904\u7406\u4fe1\u606f\u6216\u9762\u5bf9\u589e\u52a0\u7684\u590d\u6742\u6027\u65f6\uff0c\u6027\u80fd\u4f1a\u663e\u8457\u4e0b\u964d\u3002\\n\\n### \u4e3a\u4ec0\u4e48\u4f1a\u8fd9\u6837\\n\\n\u8fd9\u5f52\u7ed3\u4e8e\u57fa\u672c\u7ea6\u675f\uff1a\\n\\n1. **\u6ce8\u610f\u529b\u7a00\u91ca** - Transformer \u6ce8\u610f\u529b\u6709 N\xb2 \u7684\u590d\u6742\u5ea6\u3002\u66f4\u591a\u4ee4\u724c = \u66f4\u96be\u4e13\u6ce8\u4e8e\u91cd\u8981\u5185\u5bb9\u3002\\n\\n2. **\u4e0a\u4e0b\u6587\u8870\u9000** - \u5728\u5927\u578b\u4e0a\u4e0b\u6587\u4e2d\uff0c\u6a21\u578b\u5f00\u59cb\u5ffd\u7565\u8bad\u7ec3\uff0c\u53ea\u662f\u91cd\u590d\u4e0a\u4e0b\u6587\u5386\u53f2\u4e2d\u7684\u6a21\u5f0f\u3002\u5b83\u4eec\u53d8\u5f97\u4e0d\u90a3\u4e48\u667a\u80fd\uff0c\u800c\u4e0d\u662f\u66f4\u667a\u80fd\u3002\\n\\n3. **\u9009\u9879\u8fc7\u8f7d** - \u592a\u591a\u9009\u62e9\uff08\u5de5\u5177\u3001\u6a21\u5f0f\u3001\u65b9\u6cd5\uff09\u5bfc\u81f4\u9519\u8bef\u7684\u9009\u62e9\u3002\u8fd9\u4e0d\u662f AI \u72ec\u6709\u7684\u2014\u2014\u8fd9\u662f\u4e00\u79cd\u8ba4\u77e5\u7ea6\u675f\u3002\\n\\n4. **\u4ee4\u724c\u7ecf\u6d4e\u5b66** - \u6bcf\u4e2a\u989d\u5916\u7684\u4ee4\u724c\u90fd\u9700\u8981\u91d1\u94b1\u548c\u65f6\u95f4\u3002\u4e00\u4e2a 2,000 \u884c\u7684\u89c4\u8303\u6bd4\u4e00\u4e2a 300 \u884c\u7684\u89c4\u8303\u5904\u7406\u6210\u672c\u9ad8 6 \u500d\u3002\\n\\n### \u8fd9\u5bf9\u4f60\u610f\u5473\u7740\u4ec0\u4e48\\n\\n\u5f53\u4f60\u4f7f\u7528 AI \u7f16\u7801\u52a9\u624b\u65f6\uff1a\\n\\n- **Cursor\u3001Copilot\u3001Claude** \u5f00\u59cb\u72af\u57fa\u672c\u9519\u8bef\uff0c\u5728\u8f83\u5c0f\u4e0a\u4e0b\u6587\u4e0b\u4e0d\u4f1a\u72af\u8fd9\u4e9b\u9519\u8bef\\n- **\u4ee3\u7801\u751f\u6210**\u53d8\u5f97\u4e0d\u592a\u51c6\u786e\uff0c\u66f4\u5bb9\u6613\u4e0e\u4f60\u7684\u9700\u6c42\u76f8\u77db\u76fe\\n- **\u54cd\u5e94\u901f\u5ea6\u53d8\u6162**\uff0c\u56e0\u4e3a\u6a21\u578b\u5904\u7406\u66f4\u591a\u65e0\u5173\u4fe1\u606f\\n- **\u6210\u672c\u7ebf\u6027\u589e\u957f**\uff0c\u4e0e\u4e0a\u4e0b\u6587\u5927\u5c0f\u6210\u6b63\u6bd4\\n- **\u4f60\u82b1\u66f4\u591a\u65f6\u95f4**\u4fee\u590d AI \u9519\u8bef\uff0c\u800c\u4e0d\u662f\u4ece AI \u534f\u52a9\u4e2d\u8282\u7701\u65f6\u95f4\\n\\n\u8bbd\u523a\u7684\u662f\uff1a\u4f60\u5199\u8be6\u7ec6\u7684\u89c4\u8303\u6765\u5e2e\u52a9 AI\uff0c\u4f46\u7ec6\u8282\u5374\u8ba9 AI \u53d8\u5dee\u3002\\n\\n## \u89e3\u51b3\u65b9\u6848\uff1a\u4e0a\u4e0b\u6587\u5de5\u7a0b\\n\\n\u4e0a\u4e0b\u6587\u5de5\u7a0b\u662f\u7ba1\u7406 AI \u5de5\u4f5c\u8bb0\u5fc6\u4ee5\u6700\u5927\u5316\u6548\u679c\u7684\u5b9e\u8df5\u3002\u5b83\u4e0d\u662f\u5173\u4e8e\u538b\u7f29\u5230\u4e0a\u4e0b\u6587\u9650\u5236\u5185\u2014\u2014\u800c\u662f\u5173\u4e8e **\u5728\u4efb\u4f55\u89c4\u6a21\u4e0b\u4fdd\u6301 AI \u6027\u80fd**\u3002\\n\\n\u4ee5\u4e0b\u662f\u56db\u79cd\u5b9e\u9645\u6709\u6548\u7684\u7b56\u7565\uff0c\u6709\u7814\u7a76\u548c\u5b9e\u9645\u4f7f\u7528\u7684\u652f\u6301\uff1a\\n\\n### 1. \u5206\u533a\uff08Partition\uff09- \u62c6\u5206\u5e76\u9009\u62e9\u6027\u52a0\u8f7d\\n\\n**\u5b83\u662f\u4ec0\u4e48**\uff1a\u5c06\u5185\u5bb9\u5206\u89e3\u4e3a\u96c6\u4e2d\u7684\u5757\uff0c\u53ea\u52a0\u8f7d\u5f53\u524d\u4efb\u52a1\u6240\u9700\u7684\u5185\u5bb9\u3002\\n\\n**\u793a\u4f8b**\uff1a\\n```\\n# \u4e0d\u662f\u4e00\u4e2a 1,200 \u884c\u7684\u89c4\u8303\uff1a\\nspecs/dashboard/README.md          (200 \u884c - \u6982\u8ff0)\\nspecs/dashboard/DESIGN.md          (350 \u884c - \u67b6\u6784)\\nspecs/dashboard/IMPLEMENTATION.md  (150 \u884c - \u8ba1\u5212)\\nspecs/dashboard/TESTING.md         (180 \u884c - \u6d4b\u8bd5)\\n\\n# AI \u53ea\u52a0\u8f7d\u5b83\u9700\u8981\u7684\u5185\u5bb9\\n# \u505a\u67b6\u6784\uff1f\u53ea\u8bfb DESIGN.md\\n# \u7f16\u5199\u6d4b\u8bd5\uff1f\u53ea\u8bfb TESTING.md\\n```\\n\\n**\u597d\u5904**\uff1aAI \u5904\u7406 200-350 \u884c\u800c\u4e0d\u662f 1,200 \u884c\u3002\u66f4\u5feb\u3001\u66f4\u96c6\u4e2d\u3001\u66f4\u5c11\u9519\u8bef\u3002\\n\\n### 2. \u7cbe\u7b80\uff08Compact\uff09- \u53bb\u9664\u5197\u4f59\\n\\n**\u5b83\u662f\u4ec0\u4e48**\uff1a\u6d88\u9664\u91cd\u590d\u6216\u53ef\u63a8\u65ad\u7684\u5185\u5bb9\u3002\\n\\n**\u4e4b\u524d**\uff1a\\n```markdown\\n## \u8eab\u4efd\u9a8c\u8bc1\\n\u8eab\u4efd\u9a8c\u8bc1\u7cfb\u7edf\u4f7f\u7528 JWT \u4ee4\u724c\u3002JWT \u4ee4\u724c\u662f\\n\u884c\u4e1a\u6807\u51c6\uff0c\u63d0\u4f9b\u65e0\u72b6\u6001\u8eab\u4efd\u9a8c\u8bc1\u3002JWT \\n\u4ee4\u724c\u7684\u597d\u5904\u662f\u5b83\u4eec\u4e0d\u9700\u8981\u670d\u52a1\u5668\u7aef\\n\u4f1a\u8bdd\u5b58\u50a8...\\n\\n## \u5b9e\u73b0\\n\u6211\u4eec\u5c06\u5b9e\u73b0 JWT \u8eab\u4efd\u9a8c\u8bc1\u3002\u9009\u62e9 JWT \u662f\u56e0\u4e3a...\\n[\u91cd\u590d\u76f8\u540c\u7684\u7406\u7531]\\n```\\n\\n**\u4e4b\u540e**\uff1a\\n```markdown\\n## \u8eab\u4efd\u9a8c\u8bc1\\n\u4f7f\u7528 JWT \u4ee4\u724c\uff08\u65e0\u72b6\u6001\uff0c\u65e0\u4f1a\u8bdd\u5b58\u50a8\uff09\u3002\\n\\n## \u5b9e\u73b0\\n[\u94fe\u63a5\u5230\u8eab\u4efd\u9a8c\u8bc1\u90e8\u5206\u83b7\u53d6\u7406\u7531]\\n```\\n\\n**\u597d\u5904**\uff1a\u66f4\u9ad8\u7684\u4fe1\u566a\u6bd4\u3002AI \u4e13\u6ce8\u4e8e\u72ec\u7279\u4fe1\u606f\uff0c\u800c\u4e0d\u662f\u91cd\u590d\u3002\\n\\n### 3. \u538b\u7f29\uff08Compress\uff09- \u603b\u7ed3\u5df2\u5b8c\u6210\u7684\u5de5\u4f5c\\n\\n**\u5b83\u662f\u4ec0\u4e48**\uff1a\u538b\u7f29\u5df2\u5b8c\u6210\u7684\u5de5\u4f5c\uff0c\u540c\u65f6\u4fdd\u7559\u5173\u952e\u51b3\u7b56\u3002\\n\\n**\u4e4b\u524d**\uff1a\\n```markdown\\n## \u7b2c 1 \u9636\u6bb5\uff1a\u57fa\u7840\u8bbe\u65bd\u8bbe\u7f6e\\n\u8bbe\u7f6e\u9879\u76ee\u7ed3\u6784\uff1a\\n- \u521b\u5efa src/ \u76ee\u5f55\\n- \u521b\u5efa tests/ \u76ee\u5f55\\n- \u4f7f\u7528 tsconfig.json \u914d\u7f6e TypeScript\\n- \u4f7f\u7528 .eslintrc \u8bbe\u7f6e ESLint\\n[50 \u884c\u8be6\u7ec6\u6b65\u9aa4...]\\n```\\n\\n**\u4e4b\u540e**\uff08\u5b8c\u6210\u540e\uff09\uff1a\\n```markdown\\n## \u2705 \u7b2c 1 \u9636\u6bb5\uff1a\u57fa\u7840\u8bbe\u65bd\uff08\u5b8c\u6210\u4e8e 2025-10-15\uff09\\n\u5efa\u7acb\u4e86 TypeScript\u3001\u6d4b\u8bd5\u548c CI \u7684\u9879\u76ee\u7ed3\u6784\u3002\\n\u8be6\u60c5\u89c1\u63d0\u4ea4 abc123\u3002\\n```\\n\\n**\u597d\u5904**\uff1a\u4fdd\u7559\u9879\u76ee\u5386\u53f2\uff0c\u65e0\u9700\u81c3\u80bf\u3002AI \u77e5\u9053\u53d1\u751f\u4e86\u4ec0\u4e48\uff0c\u800c\u4e0d\u4f1a\u6df9\u6ca1\u5728\u7ec6\u8282\u4e2d\u3002\\n\\n### 4. \u9694\u79bb\uff08Isolate\uff09- \u5206\u79bb\u65e0\u5173\u5173\u6ce8\u70b9\\n\\n**\u5b83\u662f\u4ec0\u4e48**\uff1a\u5c06\u72ec\u7acb\u529f\u80fd\u79fb\u52a8\u5230\u5355\u72ec\u7684\u89c4\u8303\u4e2d\uff0c\u5e76\u5efa\u7acb\u6e05\u6670\u7684\u5173\u7cfb\u3002\\n\\n**\u4e4b\u524d**\uff1a\u4e00\u4e2a 1,200 \u884c\u7684\u89c4\u8303\u6db5\u76d6\u4eea\u8868\u677f UI\u3001\u6307\u6807 API\u3001\u5065\u5eb7\u8bc4\u5206\u7b97\u6cd5\u548c\u56fe\u8868\u5e93\u8bc4\u4f30\u3002\\n\\n**\u4e4b\u540e**\uff1a\u56db\u4e2a\u96c6\u4e2d\u7684\u89c4\u8303\uff0c\u6bcf\u4e2a\u5c11\u4e8e 400 \u884c\uff1a\\n- `dashboard-ui` - \u7528\u6237\u754c\u9762\u548c\u4ea4\u4e92\\n- `metrics-api` - \u6570\u636e\u7aef\u70b9\u8bbe\u8ba1\\n- `health-scoring` - \u7b97\u6cd5\u8be6\u60c5\\n- `chart-evaluation` - \u5e93\u6bd4\u8f83\uff08\u51b3\u7b56\u540e\u53ef\u5f52\u6863\uff09\\n\\n**\u597d\u5904**\uff1a\u72ec\u7acb\u6f14\u8fdb\u3002\u5f53\u7b97\u6cd5\u6539\u53d8\u65f6\uff0cUI \u89c4\u8303\u4fdd\u6301\u4e0d\u53d8\u3002\\n\\n### \u5173\u952e\u6d1e\u5bdf\\n\\n**\u4fdd\u6301\u4e0a\u4e0b\u6587\u5bc6\u96c6\uff08\u9ad8\u4fe1\u53f7\uff09\uff0c\u800c\u4e0d\u4ec5\u4ec5\u662f\u5c0f\u3002**\\n\\n\u8fd9\u4e0d\u662f\u5173\u4e8e\u4efb\u610f\u7684\u884c\u6570\u9650\u5236\u3002\u8fd9\u662f\u5173\u4e8e\u5220\u9664\u4efb\u4f55\u4e0d\u76f4\u63a5\u5f71\u54cd\u5f53\u524d\u51b3\u7b56\u7684\u5185\u5bb9\u3002\u6bcf\u4e2a\u4e0d\u5e2e\u52a9 AI \u505a\u51fa\u66f4\u597d\u9009\u62e9\u7684\u8bcd\u90fd\u5728\u8ba9\u5b83\u53d8\u5dee\u3002\\n\\n## \u4ece\u5b9e\u8df5\u4e2d\u83b7\u5f97\u7684\u771f\u5b9e\u7ed3\u679c\\n\\n\u6211\u4eec\u4f7f\u7528 HarnSpec \u672c\u8eab\u6765\u6784\u5efa HarnSpec\u2014\u2014\u8fd9\u662f\u5bf9\u8fd9\u79cd\u65b9\u6cd5\u8bba\u662f\u5426\u771f\u6b63\u6709\u6548\u7684\u7ec8\u6781\u6d4b\u8bd5\u3002\\n\\n**\u901f\u5ea6**\uff1a\u4ece\u96f6\u5230\u751f\u4ea7 10 \u5929\\n- \u5177\u6709 15+ \u547d\u4ee4\u7684\u529f\u80fd\u9f50\u5168\u7684 CLI\\n- \u7528\u4e8e Cursor\uff0cGitHub Copilot \u96c6\u6210\u7684 MCP \u670d\u52a1\u5668\\n- \u5e26\u6709\u7efc\u5408\u6307\u5357\u7684\u6587\u6863\u7f51\u7ad9\\n- \u7f16\u5199\u5e76\u5b9e\u73b0\u4e86 [60 \u591a\u4e2a\u89c4\u8303](https://github.com/codervisor/harnspec/tree/main/specs)\uff0c\u4f7f\u7528 AI \u4ee3\u7406\\n\\n**\u7136\u540e\u6211\u4eec\u8fdd\u53cd\u4e86\u81ea\u5df1\u7684\u539f\u5219**\uff1a\u4e00\u4e9b\u89c4\u8303\u589e\u957f\u5230 1,166 \u884c\u3002\u6211\u4eec\u9047\u5230\u4e86\u6211\u4eec\u6b63\u5728\u89e3\u51b3\u7684\u786e\u5207\u95ee\u9898\uff1a\\n- AI \u4ee3\u7406\u5728\u7f16\u8f91\u671f\u95f4\u5f00\u59cb\u7834\u574f\u89c4\u8303\\n- \u4ee3\u7801\u751f\u6210\u53d8\u5f97\u4e0d\u592a\u53ef\u9760\\n- \u54cd\u5e94\u901f\u5ea6\u660e\u663e\u53d8\u6162\\n- \u6211\u4eec\u82b1\u66f4\u591a\u65f6\u95f4\u4fee\u590d\u9519\u8bef\\n\\n**\u6211\u4eec\u5e94\u7528\u4e86\u4e0a\u4e0b\u6587\u5de5\u7a0b**\uff1a\u62c6\u5206\u5927\u578b\u89c4\u8303\uff0c\u7cbe\u7b80\u5197\u4f59\u5185\u5bb9\uff0c\u538b\u7f29\u5386\u53f2\u90e8\u5206\u3002\\n- \u6700\u5927\u7684\u89c4\u8303\u4ece 1,166 \u884c \u2192 378 \u884c\uff08\u6700\u5927\u5206\u533a\uff09\\n- AI \u4ee3\u7406\u518d\u6b21\u53ef\u9760\u5de5\u4f5c\\n- \u66f4\u5feb\u7684\u8fed\u4ee3\uff0c\u51c6\u786e\u7684\u8f93\u51fa\\n- \u53ef\u4ee5\u81ea\u4fe1\u5730\u8bf4\uff1a\\"\u6211\u4eec\u5b9e\u8df5\u6211\u4eec\u6240\u5ba3\u626c\u7684\\"\\n\\n### \u4f60\u5c06\u770b\u5230\u7684\u5177\u4f53\u597d\u5904\\n\\n\u5f53\u4f60\u5c06\u4e0a\u4e0b\u6587\u5de5\u7a0b\u5e94\u7528\u5230\u4f60\u7684\u89c4\u8303\u65f6\uff1a\\n\\n- \u2705 **\u66f4\u5c11\u7684 AI \u9519\u8bef** - \u96c6\u4e2d\u7684\u4e0a\u4e0b\u6587\u4ea7\u751f\u51c6\u786e\u3001\u4e00\u81f4\u7684\u8f93\u51fa\\n- \u2705 **\u66f4\u5feb\u7684\u8fed\u4ee3** - \u6bcf\u6b21 AI \u8bf7\u6c42\u7684\u5904\u7406\u65f6\u95f4\u66f4\u5c11\\n- \u2705 **\u66f4\u4f4e\u7684\u6210\u672c** - \u66f4\u5c11\u7684\u4ee4\u724c = \u66f4\u4fbf\u5b9c\u7684 API \u8c03\u7528\uff082,000\u2192300 \u884c\u51cf\u5c11\u53ef\u8282\u7701 6 \u500d\uff09\\n- \u2705 **\u66f4\u597d\u7684\u7406\u89e3** - AI \u5b9e\u9645\u9075\u5faa\u4f60\u7684\u9700\u6c42\uff0c\u800c\u4e0d\u662f\u5e7b\u89c9\\n- \u2705 **\u4eba\u7c7b\u53ef\u7ef4\u62a4** - 5-10 \u5206\u949f\u5185\u53ef\u4ee5\u9605\u8bfb\u7684\u89c4\u8303\u4e0e\u4ee3\u7801\u4fdd\u6301\u540c\u6b65\\n\\n### \u9002\u7528\u4e8e\u4f60\u7684\u5de5\u5177\\n\\n\u8fd9\u4e0d\u662f\u5173\u4e8e\u7279\u5b9a\u7684 AI \u5de5\u5177\u2014\u2014\u800c\u662f\u5173\u4e8e\u6240\u6709\u57fa\u4e8e transformer \u7684\u6a21\u578b\u5982\u4f55\u5904\u7406\u4e0a\u4e0b\u6587\uff1a\\n\\n- **Cursor** - \u8bfb\u53d6 markdown \u89c4\u8303\u4f5c\u4e3a\u4e0a\u4e0b\u6587\\n- **GitHub Copilot** - \u4f7f\u7528\u5de5\u4f5c\u533a\u6587\u4ef6\u8fdb\u884c\u5efa\u8bae\\n- **Claude** - \u901a\u8fc7 MCP \u670d\u52a1\u5668\u96c6\u6210\\n- **Aider** - \u5904\u7406\u9879\u76ee\u6587\u6863\\n- **Windsurf** - \u5206\u6790\u4ee3\u7801\u5e93\u4e0a\u4e0b\u6587\\n\\n\u4efb\u4f55 AI \u7f16\u7801\u52a9\u624b\u90fd\u53d7\u76ca\u4e8e\u7cbe\u5fc3\u8bbe\u8ba1\u7684\u4e0a\u4e0b\u6587\u3002\\n\\n## \u5f00\u59cb\u4f7f\u7528\\n\\nHarnSpec \u4e3a\u4f60\u63d0\u4f9b **\u65b9\u6cd5\u8bba** \u548c **\u5de5\u5177**\uff0c\u5c06\u4e0a\u4e0b\u6587\u5de5\u7a0b\u5e94\u7528\u5230\u4f60\u7684\u89c4\u8303\u4e2d\u3002\\n\\n### \u65b9\u6cd5\u8bba\\n\\n\u4e94\u4e2a\u539f\u5219\u6307\u5bfc\u51b3\u7b56\uff1a\\n\\n1. **\u4e0a\u4e0b\u6587\u7ecf\u6d4e** - \u9002\u5408\u5de5\u4f5c\u8bb0\u5fc6\uff08\u4eba\u7c7b + AI\uff09\\n2. **\u4fe1\u566a\u6bd4** - \u6bcf\u4e2a\u8bcd\u90fd\u4f20\u8fbe\u51b3\u7b56\u4fe1\u606f\\n3. **\u6e10\u8fdb\u5f0f\u62ab\u9732** - \u5728\u9700\u8981\u65f6\u6dfb\u52a0\u7ed3\u6784\\n4. **\u610f\u56fe\u4f18\u4e8e\u5b9e\u73b0** - \u6355\u83b7\u4e3a\u4ec0\u4e48\uff0c\u800c\u4e0d\u4ec5\u4ec5\u662f\u5982\u4f55\\n5. **\u5f25\u5408\u5dee\u8ddd** - \u4eba\u7c7b\u548c AI \u90fd\u80fd\u7406\u89e3\\n\\n\u8fd9\u4e9b\u4e0d\u662f\u4efb\u610f\u7684\u89c4\u5219\u2014\u2014\u5b83\u4eec\u6e90\u4e8e\u771f\u5b9e\u7684\u7ea6\u675f\uff08transformer \u6ce8\u610f\u529b\u3001\u8ba4\u77e5\u9650\u5236\u3001\u4ee4\u724c\u6210\u672c\uff09\u3002\\n\\n### \u5de5\u5177\\n\\nCLI \u547d\u4ee4\u5e2e\u52a9\u4f60\u68c0\u6d4b\u548c\u4fee\u590d\u4e0a\u4e0b\u6587\u95ee\u9898\uff1a\\n\\n```bash\\n# \u5b89\u88c5\\nnpm install -g harnspec\\n\\n# \u5728\u4f60\u7684\u9879\u76ee\u4e2d\u521d\u59cb\u5316\\ncd your-project\\nharnspec init\\n\\n# \u68c0\u6d4b\u95ee\u9898\\nharnspec validate              # \u68c0\u67e5\u95ee\u9898\\nharnspec complexity <spec>     # \u5206\u6790\u5927\u5c0f/\u7ed3\u6784\\n\\n# \u4fee\u590d\u95ee\u9898\\nharnspec split <spec>          # \u5f15\u5bfc\u5f0f\u62c6\u5206\u5de5\u4f5c\u6d41\\n\\n# \u8ddf\u8e2a\u8fdb\u5ea6\\nharnspec board                 # \u6240\u6709\u89c4\u8303\u7684\u770b\u677f\u89c6\u56fe\\n```\\n\\n### \u4ece\u7b80\u5355\u5f00\u59cb\uff0c\u6839\u636e\u9700\u8981\u589e\u957f\\n\\n**\u4e2a\u4eba\u5f00\u53d1\u8005\uff1f** \u53ea\u4f7f\u7528 `status` \u548c `created` \u5b57\u6bb5\u3002\u4fdd\u6301\u89c4\u8303\u96c6\u4e2d\u3002\\n\\n**\u5c0f\u56e2\u961f\uff1f** \u6dfb\u52a0 `tags` \u548c `priority`\u3002\u4f7f\u7528 CLI \u83b7\u5f97\u53ef\u89c1\u6027\u3002\\n\\n**\u4f01\u4e1a\uff1f** \u6dfb\u52a0\u81ea\u5b9a\u4e49\u5b57\u6bb5\uff08`epic`\u3001`sprint`\u3001`assignee`\uff09\u3002\u4e0e\u4f60\u7684\u5de5\u4f5c\u6d41\u96c6\u6210\u3002\\n\\n\u7ed3\u6784\u9002\u5e94\u4f60\u7684\u9700\u6c42\u2014\u2014\u4f60\u6c38\u8fdc\u4e0d\u4f1a\\"\u4ee5\u9632\u4e07\u4e00\\"\u6dfb\u52a0\u590d\u6742\u6027\u3002\\n\\n### \u4eca\u5929\u5c31\u8bd5\u8bd5\\n\\n```bash\\nnpm install -g harnspec\\ncd your-project\\nharnspec init\\nharnspec create user-authentication\\n```\\n\\n\u4f60\u7684 AI \u7f16\u7801\u52a9\u624b\u4f1a\u611f\u8c22\u4f60\u3002\\n\\n## \u5e95\u7ebf\\n\\n**\u4f60\u7684 AI \u5de5\u5177\u53ea\u6709\u4f60\u7ed9\u5b83\u4eec\u7684\u4e0a\u4e0b\u6587\u597d\u3002**\\n\\n\u4e00\u4e2a 2,000 \u884c\u7684\u89c4\u8303\u5373\u4f7f\u9002\u5408\u4e0a\u4e0b\u6587\u7a97\u53e3\uff0c\u4ecd\u7136\u4f1a\u4ea7\u751f\u6bd4\u5177\u6709\u76f8\u540c\u57fa\u672c\u4fe1\u606f\u7684 300 \u884c\u89c4\u8303\u66f4\u5dee\u7684\u7ed3\u679c\u3002\u8fd9\u4e0d\u662f\u5173\u4e8e\u9650\u5236\u2014\u2014\u800c\u662f\u5173\u4e8e\u6027\u80fd\u3002\\n\\n\u4e0a\u4e0b\u6587\u5de5\u7a0b\u4e0d\u662f\u4f18\u5316\u3002\u5b83\u662f\u8ba9 AI \u8f85\u52a9\u5f00\u53d1\u53ef\u9760\u5de5\u4f5c\u7684\u57fa\u7840\u3002\\n\\nHarnSpec \u662f\u4e00\u79cd\u7528\u4e8e\u4eba\u7c7b-AI \u534f\u4f5c\u7684\u8f6f\u4ef6\u89c4\u8303\u4e0a\u4e0b\u6587\u5de5\u7a0b\u65b9\u6cd5\u8bba\u3002\u5b83\u4e3a\u4f60\u63d0\u4f9b\uff1a\\n- \u6e90\u4e8e\u771f\u5b9e\u7ea6\u675f\u7684\u539f\u5219\\n- \u4ece\u4e2a\u4eba\u5230\u4f01\u4e1a\u6269\u5c55\u7684\u6a21\u5f0f\\n- \u68c0\u6d4b\u548c\u9632\u6b62\u4e0a\u4e0b\u6587\u95ee\u9898\u7684\u5de5\u5177\\n- \u4f7f\u7528\u65b9\u6cd5\u8bba\u6784\u5efa\u5de5\u5177\u7684\u8bc1\u660e\\n\\n**\u9009\u62e9**\uff1a\u7ee7\u7eed\u5199\u5927\u578b\u89c4\u8303\u5e76\u4e0e\u4e0d\u53ef\u9760\u7684 AI \u8f93\u51fa\u4f5c\u6597\u4e89\uff0c\u6216\u8005\u4e3a\u4f60\u5b9e\u9645\u4f7f\u7528\u7684\u5de5\u5177\u8bbe\u8ba1\u4f60\u7684\u4e0a\u4e0b\u6587\u3002\\n\\n---\\n\\n**\u4e86\u89e3\u66f4\u591a**\uff1a\\n- GitHub: [github.com/codervisor/harnspec](https://github.com/codervisor/harnspec)\\n- \u6587\u6863: [harnspec.dev](https://harnspec.dev)\\n- \u7814\u7a76: [\u4e0a\u4e0b\u6587\u5de5\u7a0b\u6307\u5357](/zh-Hans/docs/advanced/context-engineering)\\n\\n**\u53c2\u8003\u8d44\u6599**\uff1a\\n- [Databricks\uff1a\u957f\u4e0a\u4e0b\u6587 RAG \u6027\u80fd](https://www.databricks.com/blog/long-context-rag-performance-llms)\\n- [\u4f2f\u514b\u5229\u51fd\u6570\u8c03\u7528\u6392\u884c\u699c](https://gorilla.cs.berkeley.edu/leaderboard.html)\\n- [GraphRAG\uff1a\u67e5\u8be2\u805a\u7126\u6458\u8981\uff08\u5fae\u8f6f\u7814\u7a76\u9662\uff09](https://arxiv.org/abs/2404.16130)\\n- [NeedleBench\uff1a\u8de8\u4fe1\u606f\u5bc6\u5ea6\u7684 LLM \u68c0\u7d22](https://arxiv.org/abs/2407.11963)\\n- [\u4e0a\u4e0b\u6587\u7a97\u53e3\u6027\u80fd\u7814\u7a76](https://arxiv.org/pdf/2505.06120)"},{"id":"welcome","metadata":{"permalink":"/zh-Hans/blog/welcome","editUrl":"https://github.com/harnspec/harnspec/tree/main/docs-site/blog/2025-11-02-welcome.mdx","source":"@site/i18n/zh-Hans/docusaurus-plugin-content-blog/2025-11-02-welcome.mdx","title":"\u6b22\u8fce\u4f7f\u7528 HarnSpec","description":"\u6211\u4eec\u5f88\u9ad8\u5174\u5411\u5927\u5bb6\u4ecb\u7ecd HarnSpec\u2014\u2014\u4e00\u79cd\u4e3a\u73b0\u4ee3 AI \u9a71\u52a8\u5f00\u53d1\u8bbe\u8ba1\u7684\u8f7b\u91cf\u7ea7\u3001\u7075\u6d3b\u7684\u89c4\u8303\u9a71\u52a8\u5f00\u53d1\uff08SDD\uff09\u65b9\u6cd5\u8bba\u3002","date":"2025-11-02T00:00:00.000Z","tags":[{"inline":true,"label":"HarnSpec","permalink":"/zh-Hans/blog/tags/harn-spec"},{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"}],"readingTime":0.82,"hasTruncateMarker":true,"authors":[{"name":"Marvin Zhang","title":"HarnSpec Author","url":"https://github.com/tikazyq","imageURL":"https://github.com/tikazyq.png","key":"marvin","page":null}],"frontMatter":{"slug":"welcome","title":"\u6b22\u8fce\u4f7f\u7528 HarnSpec","authors":["marvin"],"tags":["HarnSpec","release"]},"unlisted":false,"prevItem":{"title":"\u4e3a\u4ec0\u4e48\u5927\u578b\u89c4\u8303\u4f1a\u8ba9\u4f60\u7684 AI \u4ee3\u7406\u53d8\u7b28\uff08\u4ee5\u53ca\u5982\u4f55\u89e3\u51b3\uff09","permalink":"/zh-Hans/blog/ai-agent-performance"}},"content":"\u6211\u4eec\u5f88\u9ad8\u5174\u5411\u5927\u5bb6\u4ecb\u7ecd HarnSpec\u2014\u2014\u4e00\u79cd\u4e3a\u73b0\u4ee3 AI \u9a71\u52a8\u5f00\u53d1\u8bbe\u8ba1\u7684\u8f7b\u91cf\u7ea7\u3001\u7075\u6d3b\u7684\u89c4\u8303\u9a71\u52a8\u5f00\u53d1\uff08SDD\uff09\u65b9\u6cd5\u8bba\u3002\\n\\n{/* truncate */}\\n\\n## \u4ec0\u4e48\u662f HarnSpec\uff1f\\n\\nHarnSpec \u57fa\u4e8e\u8fd9\u6837\u4e00\u4e2a\u539f\u5219\uff1a**AI \u7f16\u7801\u4ee3\u7406\u9700\u8981\u6e05\u6670\u7684\u4e0a\u4e0b\u6587\uff0c\u4f46\u4e0d\u9700\u8981\u8fc7\u591a\u7684\u6587\u6863**\u3002\u4f20\u7edf\u7684 SDD \u65b9\u6cd5\u8981\u4e48\u7f3a\u4e4f AI \u6240\u9700\u7684\u7ec6\u8282\uff0c\u8981\u4e48\u521b\u5efa\u4e86\u592a\u591a\u5f00\u9500\u5bfc\u81f4\u65e0\u4eba\u7ef4\u62a4\u3002\\n\\n## \u6838\u5fc3\u7279\u6027\\n\\n- \ud83c\udfaf **\u53ea\u5199\u91cd\u8981\u7684\u5185\u5bb9** - AI \u53ef\u4ee5\u636e\u6b64\u884c\u52a8\u7684\u6e05\u6670\u610f\u56fe\\n- \ud83e\udd16 **\u4ece\u7b2c\u4e00\u5929\u8d77\u5c31\u539f\u751f\u652f\u6301 AI** - \u9002\u914d Cursor\u3001GitHub Copilot\u3001Aider \u548c\u81ea\u5b9a\u4e49\u4ee3\u7406\\n- \ud83d\udcc8 **\u81ea\u7136\u6269\u5c55** - \u4ece\u4e2a\u4eba\u5f00\u53d1\u8005 \u2192 \u5c0f\u56e2\u961f \u2192 \u4f01\u4e1a\u7ea7\\n- \ud83d\udd27 **\u5185\u7f6e\u5de5\u4f5c\u6d41\u652f\u6301** - \u770b\u677f\u3001\u65f6\u95f4\u7ebf\u3001\u4f9d\u8d56\u8ffd\u8e2a\\n- \ud83c\udfa8 **\u4f60\u7684\u7ed3\u6784** - \u81ea\u5b9a\u4e49\u5b57\u6bb5\u3001\u7075\u6d3b\u7684\u6a21\u677f\\n\\n## \u5f00\u59cb\u4f7f\u7528\\n\\n\u67e5\u770b\u6211\u4eec\u7684[\u5feb\u901f\u5f00\u59cb\u6307\u5357](/zh-Hans/docs/guide/getting-started)\uff0c\u5f00\u59cb\u5728\u60a8\u7684\u9879\u76ee\u4e2d\u4f7f\u7528 HarnSpec\u3002\\n\\n## \u4e0b\u4e00\u6b65\uff1f\\n\\n\u6211\u4eec\u6b63\u5728\u6839\u636e\u5b9e\u9645\u4f7f\u7528\u60c5\u51b5\u6301\u7eed\u6539\u8fdb HarnSpec\u3002\u656c\u8bf7\u671f\u5f85\u66f4\u591a\u66f4\u65b0\uff01"}]}}')}}]);